class Solution(object):
    def maxPathScore(self, grid, k):
        m, n = len(grid), len(grid[0])
        INF = float('-inf')
        # dp[i][j][c] = max score at (i,j) with total cost exactly c
        dp = [[[INF] * (k + 1) for _ in range(n)] for _ in range(m)]
        dp[0][0][0] = 0

        for i in range(m):
            for j in range(n):
                cost = 0 if grid[i][j] == 0 else 1
                score = grid[i][j]
                for c in range(k + 1):
                    if i == 0 and j == 0:
                        prev = 0 if c == 0 else INF
                    else:
                        prev = INF
                        if i > 0 and dp[i-1][j][c - cost] != INF and c >= cost:
                            prev = max(prev, dp[i-1][j][c - cost])
                        if j > 0 and dp[i][j-1][c - cost] != INF and c >= cost:
                            prev = max(prev, dp[i][j-1][c - cost])
                    if prev != INF:
                        dp[i][j][c] = prev + score

        ans = max(dp[m-1][n-1][c] for c in range(k + 1))
        return ans if ans != INF else -1
